import type { FC } from 'react';
import { cn } from '@/lib/utils';
import { type IconProps, type SvgProps, sizeMap } from '../types';

export type ChameleonProps = IconProps;

const ChameleonLight: FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <rect
      x="2.5"
      y="2.5"
      width="11"
      height="11"
      rx="1.5"
      fill="#F2FCF3"
      stroke="#208A3C"
    />
    <path
      d="M8.133 11.5c1.489 0 2.765-.9 3.08-2.175h-1.016c-.314.73-1.092 1.252-2.064 1.252-1.34 0-2.306-1.074-2.306-2.577s.967-2.577 2.306-2.577c.972 0 1.75.522 2.064 1.252h1.015C10.898 5.4 9.622 4.5 8.132 4.5 6.215 4.5 4.789 5.994 4.789 8s1.426 3.5 3.345 3.5"
      fill="#208A3C"
    />
  </svg>
);

const ChameleonDark: FC<SvgProps> = ({
  size,
  className,
  title,
  role,
  'aria-label': ariaLabel,
  'aria-hidden': ariaHidden,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 16 16"
    fill="none"
    xmlns="http://www.w3.org/2000/svg"
    className={className}
    role={role}
    aria-label={ariaLabel}
    aria-hidden={ariaHidden}
  >
    {title ? <title>{title}</title> : null}
    <rect
      x="2.5"
      y="2.5"
      width="11"
      height="11"
      rx="1.5"
      fill="#253627"
      stroke="#57965C"
    />
    <path
      d="M8.133 11.5c1.489 0 2.765-.9 3.08-2.175h-1.016c-.314.73-1.092 1.252-2.064 1.252-1.34 0-2.306-1.074-2.306-2.577s.967-2.577 2.306-2.577c.972 0 1.75.522 2.064 1.252h1.015C10.898 5.4 9.622 4.5 8.132 4.5 6.215 4.5 4.789 5.994 4.789 8s1.426 3.5 3.345 3.5"
      fill="#57965C"
    />
  </svg>
);

export const Chameleon: FC<ChameleonProps> = ({
  size = 'md',
  mode = 'light',
  className,
  'aria-label': ariaLabel,
  title,
  ...props
}) => {
  const SvgComponent = mode === 'light' ? ChameleonLight : ChameleonDark;

  return (
    <SvgComponent
      size={sizeMap[size]}
      className={cn('inline-block flex-shrink-0', className)}
      title={title}
      role={ariaLabel ? 'img' : 'presentation'}
      aria-label={ariaLabel}
      aria-hidden={!ariaLabel}
      {...props}
    />
  );
};
